fun makeCoffee(sugar: Int, milk: Boolean, size: String) { 
    println("Size: $size, Milk: $milk, Sugar: $sugar")
}

fun main() {
    // Ordering doesn't matter anymore!
    makeCoffee(size = "Large", sugar = 2, milk = true)
}

fun configureSub(bread: String = "White", meat: String = "Ham", cheese: String = "Swiss", toasted: Boolean = false) {
    println("Bread: $bread, Meat: $meat, Cheese: $cheese, Toasted: $toasted")
}

fun main() {
    // Provide just the bread type, let the rest be defaults
    configureSub(bread = "Wheat")
}
